module Mix14Methods
  def self.write_mix14(w, obj)
    w.begin_object(3)
    w.write_field("amounts")
    w.begin_array(obj.amounts.length)
    obj.amounts.each do |item|
      w.next_element
      MoneyMethods.write_money(w, item)
    end
    w.end_array
    w.write_field("total")
    w.write_int64(obj.total)
    w.write_field("currency")
    w.write_string(obj.currency)
    w.end_object
  end

  def self.decode_mix14(r)
    r.begin_object
    obj = Mix14.new
    while r.has_next_field
      key = r.read_field_name
      if key == "amounts"
        tmp64 = []
        r.begin_array
        tmp64 << MoneyMethods.decode_money(r) while r.has_next_element
        r.end_array
        obj.amounts = tmp64
        next
      end
      if key == "total" then obj.total = r.read_int64; next; end
      if key == "currency" then obj.currency = r.read_string; next; end
      r.skip
    end
    r.end_object
    obj
  end
end

